import {
  Box,
  Button,
  CircularProgress,
  Modal,
  Paper,
  Stack,
  Typography,
} from '@mui/material';
import _ from 'lodash';
import React, { FC } from 'react';
import { sprintf } from 'sprintf-js';

import { translate } from '@/utils/i18n';

export type LoadingModalParam = {
  isLoading: boolean;
  title?: string;
  progress?: number;
  steps?: string[];
  currentStep?: number;
  onCancel?: () => void;
};

export const LoadingModal: FC<LoadingModalParam> = ({
  isLoading,
  title,
  progress,
  steps,
  currentStep,
  onCancel,
}) => {
  currentStep ??= 0;
  return (
    <Modal open={isLoading}>
      <Paper
        elevation={0}
        sx={{
          position: 'absolute',
          top: '50%',
          left: '50%',
          transform: 'translate(-50%, -50%)',
          backgroundColor: '#fff',
          p: 3,
        }}
      >
        <Stack direction="column" spacing={2} alignItems="center">
          {title && <Typography variant="h4">{title}</Typography>}
          <Box
            sx={{
              position: 'relative',
              display: 'inline-flex',
              marginX: 'auto',
            }}
          >
            <CircularProgress
              size={64}
              variant={_.isNil(progress) ? 'indeterminate' : 'determinate'}
              value={progress}
              sx={{
                '.MuiCircularProgress-circleDeterminate': {
                  transition: 'none',
                },
              }}
            />
            {!_.isNil(progress) && (
              <Box
                sx={{
                  top: 0,
                  left: 0,
                  bottom: 0,
                  right: 0,
                  position: 'absolute',
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center',
                }}
              >
                <Typography variant="body2" sx={{ color: 'text.secondary' }}>
                  {Math.round(progress)}%
                </Typography>
              </Box>
            )}
          </Box>
          <Box sx={{ marginX: 'auto' }}>
            {steps?.map((step, i) => (
              <Typography key={i} component="div" variant="body2">
                {i < currentStep ? '✅️' : i === currentStep ? '▶️' : '🕒️'}{' '}
                {sprintf(translate('step_format'), [i + 1])} {step}
              </Typography>
            ))}
          </Box>
          {onCancel && (
            <Button fullWidth color="neutral" onClick={onCancel}>
              {translate('button_cancel')}
            </Button>
          )}
        </Stack>
      </Paper>
    </Modal>
  );
};

